"use client";

import * as React from "react";
import { CheckCircle2, ChevronDown, ChevronRight, Flame, RefreshCcw } from "lucide-react";

import { cn } from "@/lib/utils";
import { StreakCalendar, type StreakPeriod } from "@/registry/trophy/ui/streak-calendar";

interface StreakCardProps extends React.HTMLAttributes<HTMLDivElement> {
  /** Streak periods passed through to StreakCalendar */
  streak: StreakPeriod[];
  /** Current streak value in days */
  currentStreak: number;
  /** Longest streak value in days */
  longestStreak: number;
  /** Secondary total metric value */
  total: number;
  /** Optional heading text */
  title?: string;
  /** Label for the action button */
  actionLabel?: string;
  /** Callback for action click */
  onActionClick?: () => void;
  /** Show "How streaks work" dropdown section */
  showHowItWorks?: boolean;
  /** Title for the dropdown trigger */
  howItWorksTitle?: string;
  /** Content rows shown when the dropdown is expanded */
  howItWorksItems?: string[];
  /** Initial expanded state for dropdown */
  defaultHowItWorksOpen?: boolean;
}

const StreakCard = React.forwardRef<HTMLDivElement, StreakCardProps>(
  (
    {
      className,
      streak,
      currentStreak,
      longestStreak,
      total,
      title = "Streak",
      actionLabel = "View Details",
      onActionClick,
      showHowItWorks = true,
      howItWorksTitle = "How streaks work?",
      howItWorksItems = [
        "Complete at least one activity each day to build your streak.",
        "Each day you do an activity, your streak increases.",
        "Missing a day will reset your streak to 0.",
      ],
      defaultHowItWorksOpen = false,
      ...props
    },
    ref,
  ) => {
    const [isHowItWorksOpen, setIsHowItWorksOpen] = React.useState(defaultHowItWorksOpen);
    const howItWorksContentId = React.useId();

    return (
      <section
        ref={ref}
        aria-label="Streak summary card"
        className={cn("rounded-2xl border bg-card p-6 shadow-sm", className)}
        {...props}
      >
        <header className="mb-3 flex items-center justify-between gap-3">
          <div className="flex items-center gap-2">
            <Flame className="h-6 w-6 text-warning" aria-hidden="true" />
            <h3 className="text-2xl font-semibold leading-none">{title}</h3>
          </div>
          <button
            type="button"
            onClick={onActionClick}
            className={cn(
              "inline-flex items-center gap-1 text-sm font-medium text-muted-foreground transition-colors",
              "hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
            )}
            aria-label={actionLabel}
          >
            {actionLabel}
            <ChevronRight className="h-4 w-4" />
          </button>
        </header>

        <p className="mb-4 text-5xl font-semibold leading-none tracking-tight">
          {currentStreak}
          <span className="ml-2 text-2xl font-medium text-muted-foreground">days</span>
        </p>

        <StreakCalendar
          streak={streak}
          view="week"
          startOfWeek={1}
          className="max-w-none"
        />

        <div
          className="mt-4 grid grid-cols-2 gap-4 border-t border-dashed pt-4"
          aria-label="Streak stats"
        >
          <div>
            <p className="text-sm text-muted-foreground">Longest Streak</p>
            <p className="text-3xl font-semibold leading-tight">
              {longestStreak}
              <span className="ml-1 text-2xl font-medium">days</span>
            </p>
          </div>
          <div className="text-right">
            <p className="text-sm text-muted-foreground">Total</p>
            <p className="text-3xl font-semibold leading-tight">{total}</p>
          </div>
        </div>

        {showHowItWorks && (
          <div className="mt-4 border-t pt-4">
            <button
              type="button"
              className="flex w-full items-center justify-between rounded-xl bg-muted px-4 py-3 text-left"
              onClick={() => setIsHowItWorksOpen((prev) => !prev)}
              aria-expanded={isHowItWorksOpen}
              aria-controls={howItWorksContentId}
            >
              <span className="text-lg font-semibold">{howItWorksTitle}</span>
              <ChevronDown
                className={cn(
                  "h-5 w-5 text-muted-foreground transition-transform",
                  isHowItWorksOpen && "rotate-180",
                )}
                aria-hidden="true"
              />
            </button>

            {isHowItWorksOpen && (
              <div id={howItWorksContentId} className="space-y-4 px-2 pt-4">
                {howItWorksItems.map((item, index) => {
                  const Icon = index === 0 ? CheckCircle2 : index === 1 ? Flame : RefreshCcw;
                  return (
                    <div key={`${item}-${index}`} className="flex items-start gap-3">
                      <Icon className="mt-0.5 h-5 w-5 shrink-0 text-warning" aria-hidden="true" />
                      <p className="text-lg leading-snug text-muted-foreground">{item}</p>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}
      </section>
    );
  },
);
StreakCard.displayName = "StreakCard";

export { StreakCard };
export type { StreakCardProps };

"use client";

import * as React from "react";
import { Trophy } from "lucide-react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

// Types (inlined)
interface Achievement {
  id: string;
  name: string;
  trigger: "metric" | "api" | "streak";
  description?: string | null;
  badgeUrl?: string | null;
  key?: string;
  metricId?: string;
  metricName?: string;
  metricValue?: number;
  streakLength?: number;
}

interface UserAchievement extends Achievement {
  achievedAt: string | null; // null = locked
}

// Variants
const achievementGridVariants = cva("grid", {
  variants: {
    columns: {
      2: "grid-cols-2",
      3: "grid-cols-3",
      4: "grid-cols-4",
      auto: "grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5",
    },
    gap: {
      sm: "gap-2",
      default: "gap-4",
      lg: "gap-6",
    },
  },
  defaultVariants: {
    columns: "auto",
    gap: "default",
  },
});

// Badge size mapping
const badgeSizeMap = {
  sm: "w-20",
  default: "w-28",
  lg: "w-36",
} as const;

// Props
interface AchievementGridProps
  extends
    React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof achievementGridVariants> {
  /** Array of achievements */
  achievements: UserAchievement[];
  /** Filter achievements */
  filter?: "all" | "earned" | "locked";
  /** Sort achievements */
  sortBy?: "name" | "earned" | "trigger";
  /** Size of achievement badges */
  badgeSize?: "sm" | "default" | "lg";
  /** Variant for badges */
  badgeVariant?: "card" | "badge" | "minimal";
  /** Style for locked achievements */
  lockedStyle?: "grayscale" | "silhouette" | "hidden";
  /** Custom empty state */
  emptyState?: React.ReactNode;
  /** Callback when achievement clicked */
  onAchievementClick?: (achievement: UserAchievement) => void;
}

const AchievementGrid = React.forwardRef<HTMLDivElement, AchievementGridProps>(
  (
    {
      className,
      columns,
      gap,
      achievements,
      filter = "all",
      sortBy = "name",
      badgeSize = "default",
      badgeVariant = "card",
      lockedStyle = "grayscale",
      emptyState,
      onAchievementClick,
      ...props
    },
    ref,
  ) => {
    // Filter achievements
    const filtered = React.useMemo(() => {
      switch (filter) {
        case "earned":
          return achievements.filter((a) => a.achievedAt !== null);
        case "locked":
          return achievements.filter((a) => a.achievedAt === null);
        default:
          return achievements;
      }
    }, [achievements, filter]);

    // Sort achievements
    const sorted = React.useMemo(() => {
      const copy = [...filtered];
      switch (sortBy) {
        case "earned":
          return copy.sort((a, b) => {
            if (a.achievedAt && b.achievedAt) {
              return (
                new Date(b.achievedAt).getTime() -
                new Date(a.achievedAt).getTime()
              );
            }
            if (a.achievedAt) return -1;
            if (b.achievedAt) return 1;
            return 0;
          });
        case "trigger":
          return copy.sort((a, b) => a.trigger.localeCompare(b.trigger));
        case "name":
        default:
          return copy.sort((a, b) => a.name.localeCompare(b.name));
      }
    }, [filtered, sortBy]);

    // Empty state
    if (sorted.length === 0) {
      if (emptyState) {
        return <>{emptyState}</>;
      }
      return (
        <div className="flex flex-col items-center justify-center py-12 text-center text-muted-foreground">
          <Trophy className="h-12 w-12 mb-4 opacity-50" />
          <p className="text-sm">
            {filter === "earned"
              ? "No achievements earned yet"
              : filter === "locked"
                ? "All achievements unlocked!"
                : "No achievements available"}
          </p>
        </div>
      );
    }

    const imageSize = {
      sm: "h-12 w-12",
      default: "h-16 w-16",
      lg: "h-20 w-20",
    }[badgeSize];

    const iconSize = {
      sm: "h-8 w-8",
      default: "h-10 w-10",
      lg: "h-12 w-12",
    }[badgeSize];

    return (
      <div
        ref={ref}
        className={cn(achievementGridVariants({ columns, gap }), className)}
        {...props}
      >
        {sorted.map((achievement) => {
          const isUnlocked = achievement.achievedAt !== null;

          // Skip if hidden and locked
          if (!isUnlocked && lockedStyle === "hidden") {
            return null;
          }

          return (
            <div
              key={achievement.id}
              role={onAchievementClick ? "button" : undefined}
              tabIndex={onAchievementClick ? 0 : undefined}
              onClick={() => onAchievementClick?.(achievement)}
              onKeyDown={
                onAchievementClick
                  ? (e) => {
                      if (e.key === "Enter" || e.key === " ") {
                        e.preventDefault();
                        onAchievementClick(achievement);
                      }
                    }
                  : undefined
              }
              className={cn(
                "flex flex-col items-center gap-2 rounded-lg p-4 transition-all",
                badgeVariant === "card" &&
                  "border bg-card shadow-sm hover:shadow-md",
                badgeVariant === "badge" && "bg-transparent",
                badgeVariant === "minimal" && "bg-transparent p-2",
                onAchievementClick && "cursor-pointer",
                !isUnlocked && lockedStyle === "grayscale" && "opacity-50",
              )}
            >
              {/* Badge image */}
              {achievement.badgeUrl ? (
                <img
                  src={achievement.badgeUrl}
                  alt={achievement.name}
                  className={cn(
                    imageSize,
                    "rounded-full object-cover",
                    !isUnlocked && lockedStyle === "grayscale" && "grayscale",
                    !isUnlocked &&
                      lockedStyle === "silhouette" &&
                      "brightness-0 opacity-30",
                  )}
                />
              ) : (
                <div
                  className={cn(
                    imageSize,
                    "flex items-center justify-center rounded-full",
                    isUnlocked
                      ? "bg-purple-500 text-white"
                      : "bg-muted text-muted-foreground",
                  )}
                >
                  <Trophy className={iconSize} />
                </div>
              )}

              {/* Name */}
              <span
                className={cn(
                  "text-sm text-center font-medium leading-tight",
                  !isUnlocked && "text-muted-foreground",
                )}
              >
                {achievement.name}
              </span>
            </div>
          );
        })}
      </div>
    );
  },
);
AchievementGrid.displayName = "AchievementGrid";

export { AchievementGrid, achievementGridVariants };
export type { AchievementGridProps, Achievement, UserAchievement };

"use client";

import * as React from "react";
import { Share2, Trophy, X } from "lucide-react";

import { cn } from "@/lib/utils";

// Types (inlined - only fields used by this component)
interface Achievement {
  id: string;
  name: string;
  description?: string | null;
  badgeUrl?: string | null;
}

// Props
interface AchievementUnlockedProps {
  /** Achievement that was unlocked */
  achievement: Achievement;
  /** Control open state */
  open: boolean;
  /** Callback when open state changes */
  onOpenChange: (open: boolean) => void;
  /** Callback when share button clicked */
  onShare?: () => void;
  /** Custom class for the dialog */
  className?: string;
}

const AchievementUnlocked = React.forwardRef<
  HTMLDivElement,
  AchievementUnlockedProps
>(({ achievement, open, onOpenChange, onShare, className }, ref) => {
  // Handle escape key
  React.useEffect(() => {
    if (!open) return;

    const handleEscape = (e: KeyboardEvent) => {
      if (e.key === "Escape") {
        onOpenChange(false);
      }
    };

    document.addEventListener("keydown", handleEscape);
    return () => document.removeEventListener("keydown", handleEscape);
  }, [open, onOpenChange]);

  // Prevent body scroll when open
  React.useEffect(() => {
    if (open) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "";
    }
    return () => {
      document.body.style.overflow = "";
    };
  }, [open]);

  if (!open) return null;

  return (
    <>
      {/* Backdrop */}
      <div
        className="fixed inset-0 z-50 bg-black/80"
        onClick={() => onOpenChange(false)}
        aria-hidden="true"
      />

      {/* Dialog */}
      <div
        ref={ref}
        role="dialog"
        aria-modal="true"
        aria-labelledby="achievement-title"
        className={cn(
          "fixed left-1/2 top-1/2 z-50 -translate-x-1/2 -translate-y-1/2",
          "w-full max-w-md rounded-xl bg-card p-6 shadow-2xl",
          className,
        )}
      >
        {/* Close button */}
        <button
          type="button"
          onClick={() => onOpenChange(false)}
          className="absolute right-4 top-4 rounded-sm opacity-70 ring-offset-background transition-opacity hover:opacity-100 focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2"
          aria-label="Close"
        >
          <X className="h-4 w-4" />
        </button>

        {/* Content */}
        <div className="flex flex-col items-center text-center">
          {/* Celebration text */}
          <span className="mb-4 text-sm font-medium uppercase tracking-wider text-purple-500">
            Achievement Unlocked!
          </span>

          {/* Badge */}
          <div className="relative mb-6" aria-hidden="true">
            <div className="absolute inset-0 rounded-full bg-purple-500/30 blur-xl" />

            {achievement.badgeUrl ? (
              <img
                src={achievement.badgeUrl}
                alt=""
                className="relative h-32 w-32 rounded-full object-cover ring-4 ring-purple-500/50"
              />
            ) : (
              <div className="relative flex h-32 w-32 items-center justify-center rounded-full bg-purple-500 text-white ring-4 ring-purple-500/50">
                <Trophy className="h-16 w-16" />
              </div>
            )}
          </div>

          {/* Name */}
          <h2 id="achievement-title" className="mb-2 text-2xl font-bold">
            {achievement.name}
          </h2>

          {/* Description */}
          {achievement.description && (
            <p className="mb-6 text-muted-foreground">
              {achievement.description}
            </p>
          )}

          {/* Actions */}
          <div className="flex gap-3">
            <button
              type="button"
              autoFocus
              onClick={() => onOpenChange(false)}
              className="rounded-lg bg-primary px-6 py-2.5 font-medium text-primary-foreground transition-colors hover:bg-primary/90"
            >
              Awesome!
            </button>

            {onShare && (
              <button
                type="button"
                onClick={onShare}
                className="flex items-center gap-2 rounded-lg border px-4 py-2.5 font-medium transition-colors hover:bg-muted"
              >
                <Share2 className="h-4 w-4" />
                Share
              </button>
            )}
          </div>
        </div>
      </div>
    </>
  );
});
AchievementUnlocked.displayName = "AchievementUnlocked";

export { AchievementUnlocked };
export type { AchievementUnlockedProps, Achievement };

"use client";

import * as React from "react";
import { Crown, Medal } from "lucide-react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

// Types (inlined)
interface LeaderboardRanking {
  userId: string;
  userName: string | null;
  rank: number;
  value: number;
}

// Variants
const podiumVariants = cva("flex items-end justify-center gap-2", {
  variants: {
    size: {
      sm: "gap-1",
      default: "gap-2",
      lg: "gap-4",
    },
  },
  defaultVariants: {
    size: "default",
  },
});

// Medal styles for each position
const PODIUM_CONFIG = {
  1: {
    icon: Crown,
    color: "text-yellow-500",
    bg: "bg-yellow-500/10",
    ringColor: "ring-yellow-500/50",
    height: "h-32",
    heightSm: "h-24",
    heightLg: "h-40",
  },
  2: {
    icon: Medal,
    color: "text-gray-400",
    bg: "bg-gray-400/10",
    ringColor: "ring-gray-400/50",
    height: "h-24",
    heightSm: "h-20",
    heightLg: "h-32",
  },
  3: {
    icon: Medal,
    color: "text-amber-600",
    bg: "bg-amber-600/10",
    ringColor: "ring-amber-600/50",
    height: "h-20",
    heightSm: "h-16",
    heightLg: "h-28",
  },
} as const;

// Props
interface LeaderboardPodiumProps
  extends
    React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof podiumVariants> {
  /** Top 3 rankings (expects at least 1, ideally 3) */
  rankings: LeaderboardRanking[];
  /** Show value below name */
  showValue?: boolean;
  /** Show avatar */
  showAvatar?: boolean;
  /** Medal style variant */
  medalStyle?: "classic" | "modern" | "minimal";
}

const LeaderboardPodium = React.forwardRef<
  HTMLDivElement,
  LeaderboardPodiumProps
>(
  (
    {
      className,
      size,
      rankings,
      showValue = true,
      showAvatar = true,
      medalStyle = "classic",
      ...props
    },
    ref,
  ) => {
    // Get top 3, reorder for podium display: 2nd, 1st, 3rd
    const top3 = rankings.slice(0, 3);
    const podiumOrder = [
      top3.find((r) => r.rank === 2),
      top3.find((r) => r.rank === 1),
      top3.find((r) => r.rank === 3),
    ].filter(Boolean) as LeaderboardRanking[];

    if (podiumOrder.length === 0) {
      return null;
    }

    const avatarSize = {
      sm: "h-10 w-10 text-sm",
      default: "h-14 w-14 text-lg",
      lg: "h-20 w-20 text-2xl",
    }[size ?? "default"];

    const iconSize = {
      sm: "h-4 w-4",
      default: "h-5 w-5",
      lg: "h-6 w-6",
    }[size ?? "default"];

    const textSize = {
      sm: "text-xs",
      default: "text-sm",
      lg: "text-base",
    }[size ?? "default"];

    return (
      <div
        ref={ref}
        className={cn(podiumVariants({ size }), className)}
        role="list"
        aria-label="Top 3 rankings"
        {...props}
      >
        {podiumOrder.map((ranking) => {
          const config = PODIUM_CONFIG[ranking.rank as 1 | 2 | 3];
          if (!config) return null;

          const displayName =
            ranking.userName || `User ${ranking.userId.slice(0, 6)}`;
          const podiumHeight = {
            sm: config.heightSm,
            default: config.height,
            lg: config.heightLg,
          }[size ?? "default"];

          const itemLabel = `Rank ${ranking.rank}: ${displayName}${showValue ? `, ${ranking.value.toLocaleString()}` : ""}`;

          return (
            <div
              key={ranking.userId}
              role="listitem"
              aria-label={itemLabel}
              className="flex flex-col items-center"
            >
              {/* Avatar with medal */}
              <div className="relative mb-2" aria-hidden="true">
                {showAvatar ? (
                  <div
                    className={cn(
                      "flex items-center justify-center rounded-full font-bold ring-4",
                      avatarSize,
                      config.bg,
                      config.ringColor,
                    )}
                  >
                    {displayName.charAt(0).toUpperCase()}
                  </div>
                ) : (
                  <div
                    className={cn(
                      "flex items-center justify-center rounded-full",
                      avatarSize,
                      config.bg,
                    )}
                  >
                    <config.icon className={cn(iconSize, config.color)} />
                  </div>
                )}

                {/* Medal badge */}
                {medalStyle !== "minimal" && (
                  <div
                    className={cn(
                      "absolute -bottom-1 -right-1 flex items-center justify-center rounded-full bg-background shadow-sm",
                      size === "sm"
                        ? "h-5 w-5"
                        : size === "lg"
                          ? "h-8 w-8"
                          : "h-6 w-6",
                    )}
                  >
                    <config.icon
                      className={cn(
                        config.color,
                        size === "sm"
                          ? "h-3 w-3"
                          : size === "lg"
                            ? "h-5 w-5"
                            : "h-4 w-4",
                      )}
                    />
                  </div>
                )}
              </div>

              {/* Name */}
              <span
                className={cn(
                  "font-medium text-center max-w-20 truncate",
                  textSize,
                )}
                title={displayName}
              >
                {displayName}
              </span>

              {/* Value */}
              {showValue && (
                <span
                  className={cn(
                    "text-muted-foreground tabular-nums",
                    size === "sm" ? "text-xs" : "text-sm",
                  )}
                >
                  {ranking.value.toLocaleString()}
                </span>
              )}

              {/* Podium block */}
              <div
                aria-hidden="true"
                className={cn(
                  "mt-2 w-16 rounded-t-lg",
                  size === "sm" && "w-12",
                  size === "lg" && "w-24",
                  podiumHeight,
                  config.bg,
                  medalStyle === "modern" && "rounded-t-xl",
                )}
              >
                <div
                  className={cn(
                    "flex h-8 items-center justify-center font-bold",
                    config.color,
                  )}
                >
                  {ranking.rank}
                </div>
              </div>
            </div>
          );
        })}
      </div>
    );
  },
);
LeaderboardPodium.displayName = "LeaderboardPodium";

export { LeaderboardPodium, podiumVariants };
export type { LeaderboardPodiumProps, LeaderboardRanking };

"use client";

import * as React from "react";
import { Crown, Medal, Trophy, TrendingDown, TrendingUp } from "lucide-react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

// Types (inlined)
interface LeaderboardRanking {
  userId: string;
  userName: string | null;
  rank: number;
  value: number;
}

interface LeaderboardResponse {
  id: string;
  name: string;
  key: string;
  rankBy: "points" | "streak" | "metric";
  status: string;
  description: string | null;
  rankings: LeaderboardRanking[];
  start: string;
  end: string | null;
  maxParticipants: number;
}

// Variants
const leaderboardVariants = cva("w-full", {
  variants: {
    variant: {
      table: "divide-y divide-border",
      cards: "space-y-2",
      compact: "divide-y divide-border text-sm",
    },
  },
  defaultVariants: {
    variant: "table",
  },
});

// Helper to get rank icon/medal
function getRankDisplay(rank: number) {
  switch (rank) {
    case 1:
      return { icon: Crown, color: "text-yellow-500", bg: "bg-yellow-500/10" };
    case 2:
      return { icon: Medal, color: "text-gray-400", bg: "bg-gray-400/10" };
    case 3:
      return { icon: Medal, color: "text-amber-600", bg: "bg-amber-600/10" };
    default:
      return null;
  }
}

// Props
interface LeaderboardProps
  extends
    React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof leaderboardVariants> {
  /** Full leaderboard response from Trophy API */
  leaderboard?: LeaderboardResponse;
  /** Or just provide rankings directly */
  rankings?: LeaderboardRanking[];
  /** Highlight current user */
  currentUserId?: string;
  /** Max entries to show */
  limit?: number;
  /** Show value column */
  showValue?: boolean;
  /** Label for value column */
  valueLabel?: string;
  /** Show avatar placeholder */
  showAvatar?: boolean;
  /** Custom empty state */
  emptyState?: React.ReactNode;
  /** Callback when user row clicked */
  onUserClick?: (ranking: LeaderboardRanking) => void;
}

const Leaderboard = React.forwardRef<HTMLDivElement, LeaderboardProps>(
  (
    {
      className,
      variant,
      leaderboard,
      rankings: rankingsProp,
      currentUserId,
      limit,
      showValue = true,
      valueLabel = "Score",
      showAvatar = true,
      emptyState,
      onUserClick,
      ...props
    },
    ref,
  ) => {
    const rankings = leaderboard?.rankings ?? rankingsProp ?? [];
    const displayRankings = limit ? rankings.slice(0, limit) : rankings;

    if (displayRankings.length === 0) {
      if (emptyState) return <>{emptyState}</>;
      return (
        <div className="flex flex-col items-center justify-center py-12 text-center text-muted-foreground">
          <Trophy className="h-12 w-12 mb-4 opacity-50" />
          <p className="text-sm">No rankings yet</p>
        </div>
      );
    }

    return (
      <div
        ref={ref}
        className={cn(leaderboardVariants({ variant }), className)}
        role="list"
        aria-label="Leaderboard rankings"
        {...props}
      >
        {/* Header for table variant */}
        {variant === "table" && (
          <div className="flex items-center gap-4 px-4 py-2 text-sm font-medium text-muted-foreground">
            <span className="w-12 text-center">Rank</span>
            <span className="flex-1">User</span>
            {showValue && <span className="w-20 text-right">{valueLabel}</span>}
          </div>
        )}

        {displayRankings.map((ranking) => {
          const isCurrentUser = ranking.userId === currentUserId;
          const rankDisplay = getRankDisplay(ranking.rank);
          const displayName =
            ranking.userName || `User ${ranking.userId.slice(0, 6)}`;

          return (
            <div
              key={ranking.userId}
              role="listitem"
              onClick={() => onUserClick?.(ranking)}
              onKeyDown={
                onUserClick
                  ? (e) => {
                      if (e.key === "Enter" || e.key === " ") {
                        e.preventDefault();
                        onUserClick(ranking);
                      }
                    }
                  : undefined
              }
              tabIndex={onUserClick ? 0 : undefined}
              className={cn(
                "flex items-center gap-4 px-4 py-3 transition-colors",
                variant === "cards" && "rounded-lg border bg-card",
                onUserClick && "cursor-pointer hover:bg-muted/50",
                isCurrentUser && "bg-primary/5 font-medium",
              )}
            >
              {/* Rank */}
              <div className="w-12 flex justify-center">
                {rankDisplay ? (
                  <div
                    className={cn(
                      "flex h-8 w-8 items-center justify-center rounded-full",
                      rankDisplay.bg,
                    )}
                  >
                    <rankDisplay.icon
                      className={cn("h-4 w-4", rankDisplay.color)}
                    />
                  </div>
                ) : (
                  <span className="text-muted-foreground">#{ranking.rank}</span>
                )}
              </div>

              {/* Avatar + Name */}
              <div className="flex flex-1 items-center gap-3 min-w-0">
                {showAvatar && (
                  <div
                    className={cn(
                      "flex h-8 w-8 shrink-0 items-center justify-center rounded-full text-sm font-medium",
                      isCurrentUser
                        ? "bg-primary text-primary-foreground"
                        : "bg-muted text-muted-foreground",
                    )}
                  >
                    {displayName.charAt(0).toUpperCase()}
                  </div>
                )}
                <span className="truncate">
                  {displayName}
                  {isCurrentUser && (
                    <span className="ml-2 text-xs text-muted-foreground">
                      (you)
                    </span>
                  )}
                </span>
              </div>

              {/* Value */}
              {showValue && (
                <span className="w-20 text-right tabular-nums font-medium">
                  {ranking.value.toLocaleString()}
                </span>
              )}
            </div>
          );
        })}

        {/* Show more indicator */}
        {limit && rankings.length > limit && (
          <div className="px-4 py-2 text-center text-sm text-muted-foreground">
            +{rankings.length - limit} more
          </div>
        )}
      </div>
    );
  },
);
Leaderboard.displayName = "Leaderboard";

export { Leaderboard, leaderboardVariants };
export type { LeaderboardProps, LeaderboardRanking, LeaderboardResponse };

